import java.io.*;
import java.net.*;
import javax.net.ssl.*;
public class java_52467_SocketServer_A01 {  // Server side implementation of Socket Programming in Java using standard library only without external framework or hibernate etc...  
    public static void main(String[] args) throws Exception{    
        try (SSLServerSocket sslServerSocket = new SSLServerSocket(12345, null)) {  // Create a server socket with the specified port number. This is similar to an InputStream in other words...  
            System.out.println("Listening on " + sslServerSocket);    
        while (true)    // Infinite loop for accepting client connections......     
         try(SSLConnection sslConnection = (SSLConnection)sslServerSocket.accept()) {  // Accept incoming connection from the socket...  
             System.out.println("Accepted " + sslConnection);    
           OutputStream out =  sslConnection.getOutputStream();    // Get an output stream connected to a client.....     
            DataOutputStream dataOut = new DataOutputStream(out) ;  // Create DATA OUTPUT STREAM for sending information back......  
               while (true){          // Infinite loop, will keep the connection open until we close it out or receive some sort of command...   
                   System.out.println("Waiting...");    
                 BufferedReader reader = new BufferedReader(new InputStreamReader((InputStream) sslConnection.getInputStream()));  // Create a buffering character input stream....  
                  String clientInput;            
               while ((clientInput=reader.readLine()) != null){    /// Read from the socket and print received information.....     
                   System.out.println("Received: " + clientInput);     if (clientInput .equalsIgnoreCase( "exit" )) { break;} // Exit condition......  
               }       dataOut.writeBytes ("Successfully sent\n".getBytes());// Write a string back to the connection.....     
              out.flush();    System.out.println("Closing Connection");     sslConnection .close ();break;}}} catch(IOException e){  // Catch exception if caught...  
        } finally {System.err.println ("Exception Caught!" +e );}                 }}